import { useElementSize } from '@/hooks/useElementSize';

export function KpiWidget({ label, value, trend }: { label: string; value: string; trend: number[] }) {
  return (
    <article className="@container/kpi rounded-lg bg-white p-4 shadow-sm" style={{ containerType: 'inline-size' }}>
      <p className="text-sm text-neutral-600">{label}</p>
      <p style={{ fontSize: 'clamp(1.5rem, 8cqi, 3rem)', fontWeight: 700, fontVariantNumeric: 'tabular-nums' }}>{value}</p>
      <div className="mt-2 h-10">
        <Sparkline data={trend} />
      </div>
    </article>
  );
}

function Sparkline({ data }: { data: number[] }) {
  const [ref, { width, height }] = useElementSize<HTMLDivElement>();
  if (width === 0 || data.length === 0) return <div ref={ref} className="h-full" />;
  const max = Math.max(...data);
  const min = Math.min(...data);
  const points = data.map((v, i) => `${(i / (data.length - 1)) * width},${height - ((v - min) / (max - min || 1)) * height}`).join(' ');
  return (
    <div ref={ref} className="h-full">
      <svg width={width} height={height} aria-hidden>
        <polyline points={points} fill="none" stroke="#3b82f6" strokeWidth={2} />
      </svg>
    </div>
  );
}

